# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

import os
import secrets
from flask import Flask, redirect, request, session, url_for, jsonify
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

OAUTH_CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID', 'your_client_id')
OAUTH_CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET', 'your_client_secret')
OAUTH_AUTHORIZATION_URL = os.environ.get('OAUTH_AUTHORIZATION_URL', 'https://oauth.example.com/authorize')
OAUTH_TOKEN_URL = os.environ.get('OAUTH_TOKEN_URL', 'https://oauth.example.com/token')
OAUTH_REDIRECT_URI = os.environ.get('OAUTH_REDIRECT_URI', 'http://localhost:5000/callback')

@app.route('/')
def index():
    if 'access_token' in session:
        return jsonify({
            'message': 'User is authenticated',
            'access_token': session['access_token']
        })
    return jsonify({'message': 'User is not authenticated', 'login_url': url_for('login')})

@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    
    params = {
        'client_id': OAUTH_CLIENT_ID,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'response_type': 'code',
        'scope': 'openid profile email',
        'state': state
    }
    
    authorization_url = f"{OAUTH_AUTHORIZATION_URL}?{'&'.join([f'{k}={v}' for k, v in params.items()])}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error, 'error_description': request.args.get('error_description')}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'Authorization code not found'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'State mismatch - possible CSRF attack'}), 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'client_id': OAUTH_CLIENT_ID,
        'client_secret': OAUTH_CLIENT_SECRET
    }
    
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Accept': 'application/json'
    }
    
    try:
        token_response = requests.post(
            OAUTH_TOKEN_URL,
            data=token_data,
            headers=headers,
            timeout=10
        )
        
        if token_response.status_code != 200:
            return jsonify({
                'error': 'Failed to obtain access token',
                'status_code': token_response.status_code,
                'response': token_response.text
            }), 400
        
        token_json = token_response.json()
        
        session['access_token'] = token_json.get('access_token')
        session['refresh_token'] = token_json.get('refresh_token')
        session['token_type'] = token_json.get('token_type')
        session['expires_in'] = token_json.get('expires_in')
        
        session.pop('oauth_state', None)
        
        return redirect(url_for('index'))
        
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Request failed', 'details': str(e)}), 500

@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})

@app.route('/protected')
def protected():
    if 'access_token' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify({
        'message': 'This is a protected resource',
        'access_token': session['access_token']
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)